SELECT CASE NULL WHEN FALSE THEN RAISE(IGNORE) NOTNULL ELSE CURRENT_TIME END MATCH max(CURRENT_TIMESTAMP) OVER () NOTNULL AS b FROM p JOIN t3 a ON CASE WHEN -CURRENT_DATE << CURRENT_TIME < CURRENT_TIMESTAMP & random() OVER (PARTITION BY NULL) COLLATE BINARY THEN EXISTS (VALUES (CURRENT_TIME)) >> TRUE % NOT EXISTS (SELECT * ORDER BY TRUE COLLATE RTRIM ASC NULLS FIRST) == CURRENT_DATE OR RAISE(IGNORE) NOT LIKE TRUE IS NOT DISTINCT FROM FALSE % FALSE NOT BETWEEN +CURRENT_TIME NOT NULL - (CASE FALSE IS NULL WHEN RAISE(IGNORE) THEN RAISE(IGNORE) ELSE ~CURRENT_TIME END) >> CURRENT_TIME AND TRUE COLLATE BINARY | RAISE(IGNORE) NOT NULL COLLATE NOCASE == ~RAISE(IGNORE) IS CURRENT_DATE | RAISE(IGNORE) END;
